import { describe, it, expect, vi } from "vitest";
import type { ModelMessage } from "ai";
import type {
  Message,
  CheckpointMessage,
  SessionMetadata,
  CompactionConfig,
  PruningConfig,
  ContinuationVariant,
  CompactionResult,
  PreparedCompactionV2,
  ActualTokenUsage,
  ActualTokenUsageInput,
  ContextUsage,
  TodoItem,
  StructuredState,
  SessionHeaderLine,
  MessageLine,
  CheckpointLine,
  SessionFileLine,
  CompactionSummary,
  CompactionSegment,
  PreparedCompactionSegment,
  PreparedCompaction,
} from "./compaction-types";

describe("compaction-types", () => {
  // --- Helper: Create minimal ModelMessage ---
  const createMockModelMessage = (): ModelMessage => ({
    role: "user",
    content: "test content",
  });

  // ===============================================================================
  // Message Interface
  // ===============================================================================
  describe("Message", () => {
    it("should accept valid Message object", () => {
      const message: Message = {
        createdAt: new Date("2024-01-01"),
        id: "msg-123",
        modelMessage: createMockModelMessage(),
      };
      expect(message.createdAt).toBeInstanceOf(Date);
      expect(message.id).toBe("msg-123");
      expect(message.modelMessage).toBeDefined();
    });

    it("should allow optional originalContent field", () => {
      const message: Message = {
        createdAt: new Date(),
        id: "msg-456",
        modelMessage: createMockModelMessage(),
        originalContent: "original test content",
      };
      expect(message.originalContent).toBe("original test content");
    });

    it("should work without optional originalContent", () => {
      const message: Message = {
        createdAt: new Date(),
        id: "msg-789",
        modelMessage: createMockModelMessage(),
      };
      expect(message.originalContent).toBeUndefined();
    });

    it("should enforce required fields", () => {
      // @ts-expect-error - createdAt is required
      const invalid1: Message = { id: "x", modelMessage: createMockModelMessage() };
      // @ts-expect-error - id is required
      const invalid2: Message = { createdAt: new Date(), modelMessage: createMockModelMessage() };
      // @ts-expect-error - modelMessage is required
      const invalid3: Message = { createdAt: new Date(), id: "x" };
      expect(invalid1).toBeDefined();
      expect(invalid2).toBeDefined();
      expect(invalid3).toBeDefined();
    });
  });

  // ===============================================================================
  // CheckpointMessage Interface
  // ===============================================================================
  describe("CheckpointMessage", () => {
    it("should accept valid CheckpointMessage object", () => {
      const checkpoint: CheckpointMessage = {
        createdAt: Date.now(),
        id: "ckpt-123",
        isSummary: true,
        message: createMockModelMessage(),
      };
      expect(checkpoint.createdAt).toBeTypeOf("number");
      expect(checkpoint.isSummary).toBe(true);
    });

    it("should allow optional isSummaryMessage field", () => {
      const checkpoint: CheckpointMessage = {
        createdAt: Date.now(),
        id: "ckpt-456",
        isSummary: false,
        isSummaryMessage: true,
        message: createMockModelMessage(),
      };
      expect(checkpoint.isSummaryMessage).toBe(true);
    });

    it("should allow optional originalContent field", () => {
      const checkpoint: CheckpointMessage = {
        createdAt: Date.now(),
        id: "ckpt-789",
        isSummary: true,
        message: createMockModelMessage(),
        originalContent: "original content",
      };
      expect(checkpoint.originalContent).toBe("original content");
    });

    it("should accept false for isSummary", () => {
      const checkpoint: CheckpointMessage = {
        createdAt: Date.now(),
        id: "ckpt-false",
        isSummary: false,
        message: createMockModelMessage(),
      };
      expect(checkpoint.isSummary).toBe(false);
    });
  });

  // ===============================================================================
  // SessionMetadata Interface
  // ===============================================================================
  describe("SessionMetadata", () => {
    it("should accept valid SessionMetadata object", () => {
      const metadata: SessionMetadata = {
        completionTokens: 100,
        createdAt: Date.now(),
        promptTokens: 200,
        sessionId: "session-123",
        summaryMessageId: null,
        updatedAt: Date.now(),
      };
      expect(metadata.completionTokens).toBe(100);
      expect(metadata.promptTokens).toBe(200);
      expect(metadata.summaryMessageId).toBeNull();
    });

    it("should allow string for summaryMessageId", () => {
      const metadata: SessionMetadata = {
        completionTokens: 50,
        createdAt: Date.now(),
        promptTokens: 100,
        sessionId: "session-456",
        summaryMessageId: "summary-msg-789",
        updatedAt: Date.now(),
      };
      expect(metadata.summaryMessageId).toBe("summary-msg-789");
    });

    it("should calculate total tokens", () => {
      const metadata: SessionMetadata = {
        completionTokens: 150,
        createdAt: Date.now(),
        promptTokens: 250,
        sessionId: "session-abc",
        summaryMessageId: null,
        updatedAt: Date.now(),
      };
      expect(metadata.completionTokens + metadata.promptTokens).toBe(400);
    });
  });

  // ===============================================================================
  // CompactionConfig Interface
  // ===============================================================================
  describe("CompactionConfig", () => {
    it("should accept empty config (all optional)", () => {
      const config: CompactionConfig = {};
      expect(config.contextLimit).toBeUndefined();
      expect(config.enabled).toBeUndefined();
    });

    it("should accept all optional fields", () => {
      const config: CompactionConfig = {
        contextLimit: 128000,
        enabled: true,
        getStructuredState: () => "state",
        keepRecentTokens: 2000,
        maxTokens: 8000,
        reserveTokens: 2000,
        speculativeStartRatio: 0.5,
        summarizeFn: async (msgs) => "summary",
        thresholdRatio: 0.5,
      };
      expect(config.contextLimit).toBe(128000);
      expect(config.enabled).toBe(true);
      expect(config.keepRecentTokens).toBe(2000);
      expect(config.maxTokens).toBe(8000);
      expect(config.reserveTokens).toBe(2000);
      expect(config.speculativeStartRatio).toBe(0.5);
      expect(config.thresholdRatio).toBe(0.5);
    });

    it("should allow getStructuredState callback", () => {
      const getState = vi.fn(() => "structured state");
      const config: CompactionConfig = { getStructuredState: getState };
      expect(config.getStructuredState?.()).toBe("structured state");
    });

    it("should allow getStructuredState to return undefined", () => {
      const config: CompactionConfig = { getStructuredState: () => undefined };
      expect(config.getStructuredState?.()).toBeUndefined();
    });

    it("should allow summarizeFn callback", async () => {
      const summarizeFn = vi.fn(async (msgs: ModelMessage[], prev?: string) => "summarized");
      const config: CompactionConfig = { summarizeFn };
      const result = await config.summarizeFn?.([createMockModelMessage()], "previous");
      expect(result).toBe("summarized");
    });

    it("should have correct default values per JSDoc", () => {
      const config: CompactionConfig = {};
      // Default values documented:
      // contextLimit: 128000 (but undefined when not set)
      // enabled: false (but undefined when not set)
      // keepRecentTokens: 2000 (but undefined when not set)
      // maxTokens: 8000 (but undefined when not set)
      // reserveTokens: 2000 (but undefined when not set)
      // speculativeStartRatio: 0.5 (but undefined when not set)
      // thresholdRatio: 0.5 (but undefined when not set)
      expect(config.contextLimit).toBeUndefined();
      expect(config.enabled).toBeUndefined();
      expect(config.keepRecentTokens).toBeUndefined();
      expect(config.maxTokens).toBeUndefined();
      expect(config.reserveTokens).toBeUndefined();
      expect(config.speculativeStartRatio).toBeUndefined();
      expect(config.thresholdRatio).toBeUndefined();
    });

    it("should accept minimum values (0)", () => {
      const config: CompactionConfig = {
        contextLimit: 0,
        keepRecentTokens: 0,
        maxTokens: 0,
        reserveTokens: 0,
        thresholdRatio: 0,
      };
      expect(config.contextLimit).toBe(0);
      expect(config.keepRecentTokens).toBe(0);
      expect(config.maxTokens).toBe(0);
      expect(config.reserveTokens).toBe(0);
      expect(config.thresholdRatio).toBe(0);
    });

    it("should accept ratio boundary values", () => {
      const config: CompactionConfig = {
        speculativeStartRatio: 0.15,
        speculativeStartRatio: 0.95,
        thresholdRatio: 0,
        thresholdRatio: 1,
      };
      expect(config.speculativeStartRatio).toBe(0.95);
      expect(config.thresholdRatio).toBe(1);
    });
  });

  // ===============================================================================
  // PruningConfig Interface
  // ===============================================================================
  describe("PruningConfig", () => {
    it("should accept empty config", () => {
      const config: PruningConfig = {};
      expect(config.enabled).toBeUndefined();
      expect(config.minSavingsTokens).toBeUndefined();
      expect(config.protectedToolNames).toBeUndefined();
      expect(config.protectRecentTokens).toBeUndefined();
      expect(config.replacementText).toBeUndefined();
    });

    it("should accept full config", () => {
      const config: PruningConfig = {
        enabled: true,
        minSavingsTokens: 200,
        protectedToolNames: ["tool1", "tool2"],
        protectRecentTokens: 2000,
        replacementText: "[output pruned — too large]",
      };
      expect(config.enabled).toBe(true);
      expect(config.minSavingsTokens).toBe(200);
      expect(config.protectedToolNames).toEqual(["tool1", "tool2"]);
      expect(config.protectRecentTokens).toBe(2000);
      expect(config.replacementText).toBe("[output pruned — too large]");
    });

    it("should have correct default values per JSDoc", () => {
      const config: PruningConfig = {};
      expect(config.enabled).toBeUndefined(); // default: false
      expect(config.minSavingsTokens).toBeUndefined(); // default: 200
      expect(config.protectRecentTokens).toBeUndefined(); // default: 2000
      expect(config.replacementText).toBeUndefined(); // default: "[output pruned — too large]"
    });

    it("should allow empty protectedToolNames array", () => {
      const config: PruningConfig = { protectedToolNames: [] };
      expect(config.protectedToolNames).toEqual([]);
    });
  });

  // ===============================================================================
  // ContinuationVariant Type
  // ===============================================================================
  describe("ContinuationVariant", () => {
    it("should accept 'manual' variant", () => {
      const variant: ContinuationVariant = "manual";
      expect(variant).toBe("manual");
    });

    it("should accept 'auto-with-replay' variant", () => {
      const variant: ContinuationVariant = "auto-with-replay";
      expect(variant).toBe("auto-with-replay");
    });

    it("should accept 'tool-loop' variant", () => {
      const variant: ContinuationVariant = "tool-loop";
      expect(variant).toBe("tool-loop");
    });

    it("should not accept invalid variant", () => {
      // @ts-expect-error - invalid variant
      const invalid: ContinuationVariant = "invalid";
      expect(invalid).toBe("invalid");
    });
  });

  // ===============================================================================
  // CompactionResult Interface
  // ===============================================================================
  describe("CompactionResult", () => {
    it("should accept minimal valid result", () => {
      const result: CompactionResult = {
        success: true,
        tokensAfter: 1000,
        tokensBefore: 5000,
      };
      expect(result.success).toBe(true);
      expect(result.tokensAfter).toBe(1000);
      expect(result.tokensBefore).toBe(5000);
    });

    it("should accept result with all optional fields", () => {
      const result: CompactionResult = {
        continuationVariant: "auto-with-replay",
        reason: "success",
        success: true,
        summaryMessageId: "summary-123",
        tokensAfter: 800,
        tokensBefore: 4000,
      };
      expect(result.continuationVariant).toBe("auto-with-replay");
      expect(result.reason).toBe("success");
      expect(result.summaryMessageId).toBe("summary-123");
    });

    it("should accept failure result", () => {
      const result: CompactionResult = {
        success: false,
        reason: "Insufficient tokens to compact",
        tokensAfter: 5000,
        tokensBefore: 5000,
      };
      expect(result.success).toBe(false);
      expect(result.reason).toBe("Insufficient tokens to compact");
    });

    it("should allow undefined optional fields", () => {
      const result: CompactionResult = {
        success: true,
        tokensAfter: 0,
        tokensBefore: 0,
      };
      expect(result.continuationVariant).toBeUndefined();
      expect(result.reason).toBeUndefined();
      expect(result.summaryMessageId).toBeUndefined();
    });

    it("should calculate token delta", () => {
      const result: CompactionResult = {
        success: true,
